        'status': 'Active',
        'fine_amount': 0.0
    }

    borrowings[new_borrow_id] = new_borrow

    # Update book status
    book['status'] = 'Borrowed'
    save_books(books)
    save_borrowings(borrowings)

    context = {
        'success': True,
        'book': {
