from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Helper functions to load and save data

def load_articles():
    articles = []
    try:
        with open(os.path.join(DATA_DIR, 'articles.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 7:
                    continue
                article_id = int(parts[0])
                title = parts[1]
                author = parts[2]
                category = parts[3]
                content = parts[4]
                date = parts[5]
                views = int(parts[6])
                articles.append({
                    'article_id': article_id,
                    'title': title,
                    'author': author,
                    'category': category,
                    'content': content,
                    'date': date,
                    'views': views
                })
    except FileNotFoundError:
        pass
    return articles


def load_categories():
    categories = []
    try:
        with open(os.path.join(DATA_DIR, 'categories.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 3:
                    continue
                category_id = int(parts[0])
                category_name = parts[1]
                description = parts[2]
                categories.append({
                    'category_id': category_id,
                    'category_name': category_name,
                    'description': description
                })
    except FileNotFoundError:
        pass
    return categories


def load_bookmarks():
    bookmarks = []
    try:
        with open(os.path.join(DATA_DIR, 'bookmarks.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 4:
                    continue
                bookmark_id = int(parts[0])
                article_id = int(parts[1])
                article_title = parts[2]
                bookmarked_date = parts[3]
                bookmarks.append({
                    'bookmark_id': bookmark_id,
                    'article_id': article_id,
                    'article_title': article_title,
                    'bookmarked_date': bookmarked_date
                })
    except FileNotFoundError:
        pass
    return bookmarks


def save_bookmarks(bookmarks):
    try:
        with open(os.path.join(DATA_DIR, 'bookmarks.txt'), 'w', encoding='utf-8') as f:
            for bm in bookmarks:
                f.write(f"{bm['bookmark_id']}|{bm['article_id']}|{bm['article_title']}|{bm['bookmarked_date']}\n")
    except:
        pass


def load_comments():
