@app.route('/articles/<int:article_id>')
def article_details(article_id):
    articles = load_articles()
    bookmarks = load_bookmarks()

    article = next((a for a in articles if a['article_id'] == article_id), None)
    if article is None:
        # Not found, return 404 page
        return "Article not found", 404

    # article: dict (article_id:int, title:str, author:str, date:str, content:str) - as per spec
    article_dict = {
        'article_id': article['article_id'],
        'title': article['title'],
        'author': article['author'],
        'date': article['date'],
        'content': article['content']
    }

    # bookmarked: bool - whether this article is bookmarked
    bookmarked = any(bm['article_id'] == article_id for bm in bookmarks)

    return render_template('article_details.html', article=article_dict, bookmarked=bookmarked)


